L''episodio esprime una miscela di leggerezza, ansia e ironia, con momenti di tensione legati alla responsabilità e al confronto generazionale, ma anche calore e affetto tra i personaggi.', 'public' from serie_tv where titolo_originale = '爱情公寓'
on conflict (serie_id, stagione, numero_episodio) do update set
  titolo_originale = excluded.titolo_originale, messa_in_onda = excluded.messa_in_onda,
  trascrizione = excluded.trascrizione, sintesi_automatica = excluded.sintesi_automatica,
  analisi_tematica_emotiva = excluded.analisi_tematica_emotiva, visibility = excluded.visibility;

insert into episodi (serie_id, stagione, numero_episodio, titolo_originale, messa_in_onda, trascrizione, sintesi_automatica, analisi_tematica_emotiva, visibility)
