with target_serie as (select id from serie_tv where titolo_originale = '爱情公寓' limit 1),
target_episode as (select episodi.id from episodi join target_serie on target_serie.id = episodi.serie_id where episodi.titolo_originale = '婚礼大乱斗 Hūnlǐ dà luàn dòu' limit 1),
target_emotion as (select id from emozioni where nome = 'Rabbia' limit 1)
insert into frasi_parole (serie_id, episodio_id, emozione_principale_id, tipo, frase_originale, immagine_rappresentativa, sintesi_automatica, classificazione_tematica_ai, note_admin, visibility)
select target_serie.id, target_episode.id, target_emotion.id, 'Frase', '变态啊你! ... 滚蛋!', null, null, null, null, 'public' from target_serie left join target_episode on true left join target_emotion on true
on conflict do nothing;
insert into frasi_emozioni (frase_id, emozione_id, intensita)
select frasi_parole.id, emozioni.id, 2 from frasi_parole join serie_tv on serie_tv.id = frasi_parole.serie_id join emozioni on emozioni.nome = 'Rabbia' where serie_tv.titolo_originale = '爱情公寓' and frasi_parole.frase_originale = '变态啊你! ... 滚蛋!'
on conflict (frase_id, emozione_id) do update set intensita = excluded.intensita;

with target_serie as (select id from serie_tv where titolo_originale = '爱情公寓' limit 1),
target_episode as (select episodi.id from episodi join target_serie on target_serie.id = episodi.serie_id where episodi.titolo_originale = '新人入住 Xīnrén rùzhù' limit 1)
insert into danmu_raw (serie_id, episodio_id, testo_originale, traduzione_italiana, data_commento, timecode_secondi, sentiment, colore, like_ricevuti, note, source_row_number)
select target_serie.id, target_episode.id, 'prova', null, null, null, null, null, null, null, 1 from target_serie left join target_episode on true
on conflict do nothing;

commit;
